    print(
        f"HARNESS RESULT: PASS\n"
        f"Run ID:          {run_id}\n"
        f"Harness version: {HARNESS_VERSION}\n"
        f"Module version:  {args.module_version}\n"
        f"Vectors:         {len(er_records)}\n"
        f"Manifest hash:   {manifest_hash[:16]}...\n"
        f"Pass record:     {pass_filepath}\n"
        f"Timestamp:       {ts}"
    )

