    if violations:
        fh.handle(
            failure_type_id="FREEZE_VIOLATION",
            detail=f"Clip chain violations detected: {violations[0][:200]}",
        )

    # -----------------------------------------------------------------------
    # PASS: Write pass record and exit 0.
    # -----------------------------------------------------------------------
    ts = _now_iso()
